//! Unit tests for the contract's own state machine: admin auth, agent
//! registration, policy updates, and the pre-verification checks in
//! `submit_spend` (stale commitment / nonce mismatch / policy mismatch).
//!
//! What these tests deliberately do NOT cover: a `submit_spend` call that
//! reaches a real, accepting `UltraHonkVerifier::verify`. That requires a
//! real Noir proof + verification key pair generated by `nargo`/`bb`
//! against `aegis-circuit`'s `spend_proof` circuit, and neither tool is
//! available in this build environment (see the repo README). The
//! `submit_spend_rejects_invalid_proof_bytes` test below confirms the
//! integration point is wired up -- a syntactically-invalid proof is
//! correctly rejected -- but it cannot exercise the accept path.

use super::*;
use soroban_sdk::testutils::Address as _;
use soroban_sdk::{Bytes, BytesN, Env};

fn setup(env: &Env) -> (Address, Address, BytesN<32>) {
    let contract_id = env.register(AegisTreasury, ());
    let admin = Address::generate(env);
    let root = BytesN::from_array(env, &[1u8; 32]);
    (contract_id, admin, root)
}

fn dummy_vk(env: &Env) -> Bytes {
    Bytes::from_array(env, &[0u8; 16])
}

#[test]
fn init_and_register_agent() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, admin, root) = setup(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);

    client.init(&admin, &root, &dummy_vk(&env));

    let commitment = BytesN::from_array(&env, &[7u8; 32]);
    client.register_agent(&admin, &1u64, &commitment);

    assert_eq!(client.get_commitment(&1u64), Some(commitment));
    assert_eq!(client.get_nonce(&1u64), 0u64);
}

#[test]
fn register_agent_rejects_non_admin() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, admin, root) = setup(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);
    client.init(&admin, &root, &dummy_vk(&env));

    let attacker = Address::generate(&env);
    let commitment = BytesN::from_array(&env, &[7u8; 32]);
    let result = client.try_register_agent(&attacker, &1u64, &commitment);

    assert_eq!(result, Err(Ok(Error::Unauthorized)));
}

