#[test]
fn update_policy_as_admin_succeeds() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, admin, root) = setup(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);
    client.init(&admin, &root, &dummy_vk(&env));

    let new_root = BytesN::from_array(&env, &[2u8; 32]);
    client.update_policy(&admin, &500u64, &new_root);
}

fn registered_agent(env: &Env) -> (Address, BytesN<32>, Address, BytesN<32>) {
    let (contract_id, admin, root) = setup(env);
    let client = AegisTreasuryClient::new(env, &contract_id);
    client.init(&admin, &root, &dummy_vk(env));
    client.update_policy(&admin, &500u64, &root);

    let commitment = BytesN::from_array(env, &[7u8; 32]);
    client.register_agent(&admin, &1u64, &commitment);
    (contract_id, root, admin, commitment)
}

fn base_public_inputs(root: &BytesN<32>, commitment: &BytesN<32>) -> SpendPublicInputs {
    SpendPublicInputs {
        old_balance_commitment: commitment.clone(),
        new_balance_commitment: commitment.clone(),
        per_tx_cap: 500,
        vendor_allowlist_root: root.clone(),
        agent_id: 1,
        agent_nonce: 0,
    }
}

#[test]
fn submit_spend_rejects_stale_commitment() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, root, _admin, commitment) = registered_agent(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);

    let wrong_commitment = BytesN::from_array(&env, &[9u8; 32]);
    let mut inputs = base_public_inputs(&root, &commitment);
    inputs.old_balance_commitment = wrong_commitment;

    let result = client.try_submit_spend(&1u64, &Bytes::from_array(&env, &[0u8; 32]), &inputs);
    assert_eq!(result, Err(Ok(Error::StaleCommitment)));
}

#[test]
fn submit_spend_rejects_nonce_mismatch() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, root, _admin, commitment) = registered_agent(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);

    let mut inputs = base_public_inputs(&root, &commitment);
    inputs.agent_nonce = 5; // agent's stored nonce is 0

    let result = client.try_submit_spend(&1u64, &Bytes::from_array(&env, &[0u8; 32]), &inputs);
    assert_eq!(result, Err(Ok(Error::NonceMismatch)));
}

