/// All the contract's own pre-checks pass (commitment, nonce, policy all
/// match on-chain state), so this reaches the real `UltraHonkVerifier`.
/// The dummy VK installed in `init` is intentionally too short to parse,
/// so this proves the verifier integration point is actually being
/// invoked rather than silently skipped.
#[test]
fn submit_spend_rejects_invalid_proof_bytes() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, root, _admin, commitment) = registered_agent(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);

    let inputs = base_public_inputs(&root, &commitment);
    let result = client.try_submit_spend(&1u64, &Bytes::from_array(&env, &[0u8; 32]), &inputs);

    assert_eq!(result, Err(Ok(Error::VkLoadFailed)));
}

#[test]
fn submit_spend_unregistered_agent_fails() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, admin, root) = setup(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);
    client.init(&admin, &root, &dummy_vk(&env));
    client.update_policy(&admin, &500u64, &root);

    let commitment = BytesN::from_array(&env, &[7u8; 32]);
    let inputs = base_public_inputs(&root, &commitment);
    let result = client.try_submit_spend(&42u64, &Bytes::from_array(&env, &[0u8; 32]), &inputs);

    assert_eq!(result, Err(Ok(Error::AgentNotRegistered)));
}

