#[test]
fn set_period_start_commitment_as_admin_is_used_by_verify_attestation() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, _root, admin, _commitment) = registered_agent(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);
    client.init_attestation_vk(&admin, &dummy_vk(&env));

    // A real historical commitment, distinct from the agent's current one --
    // simulating "24 hours ago" -- set directly rather than snapshotted.
    let historical_commitment = BytesN::from_array(&env, &[5u8; 32]);
    client.set_period_start_commitment(&admin, &1u64, &historical_commitment);

    // verify_attestation reads PeriodStartCommitment from storage, so a
    // subsequent call proceeds past NoPeriodStarted (reaches the real
    // verifier, which then rejects the dummy proof bytes) -- proving the
    // historical commitment was actually stored and used, not ignored.
    let claim = AttestationClaim { max_spend: 1000, period_label: 202602 };
    let result =
        client.try_verify_attestation(&1u64, &claim, &Bytes::from_array(&env, &[0u8; 32]));
    assert_eq!(result, Err(Ok(Error::AttestationVkLoadFailed)));
}

#[test]
fn verify_attestation_without_period_start_fails() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, _root, admin, _commitment) = registered_agent(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);
    client.init_attestation_vk(&admin, &dummy_vk(&env));

    let claim = AttestationClaim { max_spend: 1000, period_label: 202602 };
    let result =
        client.try_verify_attestation(&1u64, &claim, &Bytes::from_array(&env, &[0u8; 32]));
    assert_eq!(result, Err(Ok(Error::NoPeriodStarted)));
}

#[test]
fn verify_attestation_rejects_invalid_proof_bytes() {
    let env = Env::default();
    env.mock_all_auths();
    let (contract_id, _root, admin, _commitment) = registered_agent(&env);
    let client = AegisTreasuryClient::new(&env, &contract_id);
    client.init_attestation_vk(&admin, &dummy_vk(&env));
    client.start_attestation_period(&admin, &1u64);

    let claim = AttestationClaim { max_spend: 1000, period_label: 202602 };
    let result =
        client.try_verify_attestation(&1u64, &claim, &Bytes::from_array(&env, &[0u8; 32]));

    // Reaches the real verifier (period started, VK installed) and is
    // correctly rejected since the dummy VK is too short to parse.
    assert_eq!(result, Err(Ok(Error::AttestationVkLoadFailed)));
}
